  ('promotion-6e2f88c7-moex-00038', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-114-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '關於不當聯結禁止原則之敘述，下列何者錯誤？', '["行政處分之附款應與該處分之目的具有正當合理之關聯", "人民與行政機關締結雙務行政契約時，人民之給付與行政機關之給付應相當，並具有正當合理 之關聯", "依司法實務見解，汽車所有人繳清違規罰鍰後始得換發行車執照，並未牴觸不當聯結禁止原則", "以同意捐款勞軍，作為核發建築許可之條件，牴觸不當聯結禁止原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "125", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
